import{_ as t,o as r,c as o,a3 as i}from"./chunks/framework.LBeL10WQ.js";const h=JSON.parse('{"title":"Quick Start — Distributors","description":"","frontmatter":{"title":"Quick Start — Distributors"},"headers":[],"relativePath":"en/publishers/onboarding-quick-start.md","filePath":"en/publishers/onboarding-quick-start.md"}'),a={name:"en/publishers/onboarding-quick-start.md"};function s(n,e,l,c,u,d){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="quick-start-—-distributors" tabindex="-1">Quick Start — Distributors <a class="header-anchor" href="#quick-start-—-distributors" aria-label="Permalink to &quot;Quick Start — Distributors&quot;">​</a></h1><p>You have just joined getinside. In 3 steps (10 minutes), your profile is ready to receive your first campaigns.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>This guide is for you if:</strong> you received the getinside invitation email and want to start quickly.</p></div><hr><h2 id="step-1-—-activate-your-access-2-min" tabindex="-1">Step 1 — Activate your access (2 min) <a class="header-anchor" href="#step-1-—-activate-your-access-2-min" aria-label="Permalink to &quot;Step 1 — Activate your access (2 min)&quot;">​</a></h2><ol><li>Open the <strong>invitation email</strong> received from getinside</li><li>Click the activation link</li><li>Set your password</li><li>Log in at <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a></li></ol><blockquote><p>Your account was created by the getinside team during your demo. If you didn&#39;t receive the email, check your spam folder or contact your manager.</p></blockquote><hr><h2 id="step-2-—-configure-your-logistics-profile-5-min" tabindex="-1">Step 2 — Configure your logistics profile (5 min) <a class="header-anchor" href="#step-2-—-configure-your-logistics-profile-5-min" aria-label="Permalink to &quot;Step 2 — Configure your logistics profile (5 min)&quot;">​</a></h2><p>Before receiving campaigns, the algorithm needs two pieces of information:</p><p><strong>Workspace:</strong> Settings → Logistics</p><table tabindex="0"><thead><tr><th>Field</th><th>What to define</th></tr></thead><tbody><tr><td><strong>Warehouse address</strong></td><td>The address where physical materials (boxes, flyers) will be delivered</td></tr><tr><td><strong>Lead Time</strong></td><td>The minimum delay between reception and start of distribution (e.g., 3 days)</td></tr></tbody></table><blockquote><p>This data allows the platform to only offer you campaigns that you can honor according to your real constraints.</p></blockquote><hr><h2 id="step-3-—-create-your-first-audience-3-min" tabindex="-1">Step 3 — Create your first audience (3 min) <a class="header-anchor" href="#step-3-—-create-your-first-audience-3-min" aria-label="Permalink to &quot;Step 3 — Create your first audience (3 min)&quot;">​</a></h2><p>Your audience is what you sell to advertisers. The more precise it is, the more relevant campaigns you receive.</p><p><strong>Workspace:</strong> Monetization → Create an audience</p><p>At a minimum, enter:</p><ul><li><strong>Audience name</strong>: e.g. &quot;Women&#39;s fashion e-commerce customers 25-45 yo&quot;</li><li><strong>Average Order Value</strong> of your customers</li><li><strong>Category</strong> of your products</li><li><strong>Weekly volume</strong> of parcels (for Parcel Insert)</li></ul><blockquote><p>A complete and precise audience profile is the main attractiveness factor for advertisers. Take the time to fill it out carefully.</p></blockquote><hr><h2 id="you-are-ready-✅" tabindex="-1">You are ready ✅ <a class="header-anchor" href="#you-are-ready-✅" aria-label="Permalink to &quot;You are ready ✅&quot;">​</a></h2><p>A <strong>checkout call</strong> with the getinside team confirms your listing on the marketplace. From then on, you will receive <strong>campaign proposals</strong> directly on the platform.</p><p><strong>Golden rule to remember:</strong> You have <strong>48 business hours</strong> to respond to each proposal. Beyond that, it expires and can impact your <a href="/handbook/en/publishers/score-distributor.html">Distributor Score</a>.</p><hr><p><strong>Next steps:</strong></p><ul><li><a href="/handbook/en/publishers/onboarding-process.html">Complete onboarding process</a> — detailed operations</li><li><a href="/handbook/en/publishers/score-distributor.html">Distributor Score</a> — how to maximize your visibility</li><li><a href="/handbook/en/publishers/payouts.html">Payments &amp; Wallet</a> — understand when and how you will be paid</li></ul>',27)])])}const m=t(a,[["render",s]]);export{h as __pageData,m as default};
